              </div>
              <div>
                <h3 className="text-xl font-bold text-slate-800">Conectar Base de Datos</h3>
                <p className="text-slate-500 text-sm">Pega aquí tu URL de Google Apps Script.</p>
              </div>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700">URL de la Aplicación Web</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-green-500 text-sm"
                  placeholder="https://script.google.com/macros/s/.../exec"
                  value={url}
                  onChange={(e) => setUrl(e.target.value)}
                />
              </div>

              <button 
                onClick={handleSave}
                className="w-full bg-slate-900 hover:bg-slate-800 text-white py-4 rounded-2xl font-bold transition-all flex items-center justify-center gap-2"
              >
                <i className="fa-solid fa-cloud-arrow-up"></i> Guardar y Sincronizar
              </button>
            </div>
          </div>

          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
            <div className="flex items-center gap-4 mb-6">
              <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center">
                <i className="fa-solid fa-mobile-screen-button text-xl"></i>
