};

export default SettingsView;

import React, { useState, useEffect, useCallback } from 'react';
import { InventoryItem, Transaction, ViewType, AppConfig } from './types';
import Sidebar from './components/Sidebar';
import DashboardView from './components/DashboardView';
import InventoryView from './components/InventoryView';
import SalesView from './components/SalesView';
import ReportsView from './components/ReportsView';
import SettingsView from './components/SettingsView';
import { semanticSearch } from './geminiService';
import { syncWithSheet, mapSheetDataToInventory, SyncAction } from './spreadsheetService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('DASHBOARD');
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<AppConfig>(() => {
    const saved = localStorage.getItem('berjitsu_config');
    return saved ? JSON.parse(saved) : { spreadsheetAppUrl: '', isLinked: false };
  });

  const [searchQuery, setSearchQuery] = useState('');
  const [filteredIds, setFilteredIds] = useState<string[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isInitialLoad, setIsInitialLoad] = useState(true);
  const [lastSyncTime, setLastSyncTime] = useState<string | null>(null);

  // Función para obtener datos remotos
  const fetchRemoteData = async (targetUrl?: string) => {
    const urlToUse = targetUrl || config.spreadsheetAppUrl;
    if (!urlToUse) return;

    setIsSyncing(true);
    try {
      const rows = await syncWithSheet(urlToUse, 'READ');
      if (rows && Array.isArray(rows) && rows.length > 1) { // > 1 porque la fila 0 son cabeceras
        const mapped = mapSheetDataToInventory(rows);
        if (mapped.length > 0) {
          setInventory(mapped);
          setLastSyncTime(new Date().toLocaleTimeString());
        }
      }
    } catch (err) {
      console.error("Error al obtener datos remotos:", err);
    } finally {
      setIsSyncing(false);
    }
  };

  // 1. CARGA INICIAL (LOCAL + REMOTA)
  useEffect(() => {
    const initApp = async () => {
      // Primero cargamos lo que haya en memoria local para rapidez
      const savedInv = localStorage.getItem('berjitsu_inventory');
      const savedTransactions = localStorage.getItem('berjitsu_transactions');

      let localInv: InventoryItem[] = [];
      if (savedInv) {
        localInv = JSON.parse(savedInv);
        setInventory(localInv);
      }

      if (savedTransactions) {
        setTransactions(JSON.parse(savedTransactions));
      }

      // Si no hay nada local Y no hay link, ponemos ejemplos
      if (!savedInv && !config.isLinked) {
        setInventory([
          { id: '1', sku: 'EXE-001', name: 'Artículo de Ejemplo', description: 'Configura tu Google Sheet para ver tus datos reales', category: 'General', price: 100, cost: 50, stock: 10, lastUpdated: new Date().toISOString() }
        ]);
      }

      // Si hay link, forzamos actualización remota inmediata
      if (config.isLinked && config.spreadsheetAppUrl) {
        await fetchRemoteData(config.spreadsheetAppUrl);
      }

      setIsInitialLoad(false);
    };
    initApp();
  }, [config.isLinked]); // Re-ejecutar si cambia el estado de vinculación

  // 2. GUARDADO LOCAL AUTOMÁTICO (Cada vez que algo cambie)
  useEffect(() => {
    if (!isInitialLoad) {
      localStorage.setItem('berjitsu_inventory', JSON.stringify(inventory));
      localStorage.setItem('berjitsu_transactions', JSON.stringify(transactions));
      localStorage.setItem('berjitsu_config', JSON.stringify(config));
    }
  }, [inventory, transactions, config, isInitialLoad]);

  // Búsqueda semántica
  useEffect(() => {
    const delayDebounceFn = setTimeout(async () => {
      if (!searchQuery.trim()) {
        setFilteredIds(inventory.map(i => i.id));
        return;
      }
      setIsSearching(true);
      const lowerQuery = searchQuery.toLowerCase();
      const localMatches = inventory.filter(i => 
        i.name.toLowerCase().includes(lowerQuery) || 
        i.sku.toLowerCase().includes(lowerQuery) ||
        i.category.toLowerCase().includes(lowerQuery)
      ).map(i => i.id);

      if (localMatches.length > 0) {
        setFilteredIds(localMatches);
        setIsSearching(false);
      } else {
        const aiMatches = await semanticSearch(searchQuery, inventory);
        setFilteredIds(aiMatches);
        setIsSearching(false);
      }
    }, 400);
    return () => clearTimeout(delayDebounceFn);
  }, [searchQuery, inventory]);

  const pushToRemote = useCallback((payload: any, syncAction: SyncAction) => {
    if (config.isLinked && config.spreadsheetAppUrl) {
      syncWithSheet(config.spreadsheetAppUrl, 'WRITE', payload, syncAction);
    }
  }, [config.isLinked, config.spreadsheetAppUrl]);

  const updateStock = (itemId: string, amount: number, type: 'IN' | 'OUT') => {
    const updated = inventory.map(item => {
      if (item.id === itemId) {
        const newStock = type === 'IN' ? item.stock + amount : Math.max(0, item.stock - amount);
        return { ...item, stock: newStock, lastUpdated: new Date().toISOString() };
      }
      return item;
    });
    setInventory(updated);
    pushToRemote(updated, 'UPDATE_INVENTORY');
  };

  const handleSale = (cartItems: { itemId: string, quantity: number }[]) => {
    const updatedInv = inventory.map(item => {
      const soldItem = cartItems.find(si => si.itemId === item.id);
      if (soldItem) {
        return { ...item, stock: Math.max(0, item.stock - soldItem.quantity), lastUpdated: new Date().toISOString() };
      }
      return item;
    });

    const saleItems = cartItems.map(si => {
      const originalItem = inventory.find(i => i.id === si.itemId);
      return {
        itemId: si.itemId,
        itemName: originalItem?.name || 'Producto desconocido',
        quantity: si.quantity,
        priceAtSale: originalItem?.price || 0
      };
    });

    const total = saleItems.reduce((acc, curr) => acc + (curr.priceAtSale * curr.quantity), 0);
    const newTransaction: Transaction = {
      id: Math.random().toString(36).substr(2, 6).toUpperCase(),
      type: 'SALE',
      items: saleItems,
      totalAmount: total,
      timestamp: new Date().toISOString()
    };

    setTransactions(prev => [newTransaction, ...prev]);
    setInventory(updatedInv);

    pushToRemote(newTransaction, 'RECORD_SALE');
    pushToRemote(updatedInv, 'UPDATE_INVENTORY');
  };

  const addItem = (item: Omit<InventoryItem, 'id' | 'lastUpdated'>) => {
    const newItem: InventoryItem = {
      ...item,
      id: Math.random().toString(36).substr(2, 9),
      lastUpdated: new Date().toISOString()
    };
    const updated = [...inventory, newItem];
    setInventory(updated);
    pushToRemote(updated, 'UPDATE_INVENTORY');
  };

  const deleteItem = (id: string) => {
    const updated = inventory.filter(i => i.id !== id);
    setInventory(updated);
    pushToRemote(updated, 'UPDATE_INVENTORY');
  };

  if (isInitialLoad) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#121212]">
        <div className="text-center">
          <div className="relative mb-6">
            <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mx-auto p-1 shadow-2xl animate-pulse">
              <img src="logo.png" alt="Berjitsu Logo" className="w-full h-full object-contain" />
            </div>
            <div className="absolute inset-0 w-32 h-32 -m-4 border-4 border-green-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
          <p className="text-white font-black tracking-widest text-xl uppercase">MOV. BERJITSU</p>
          <p className="text-slate-500 text-sm mt-2">Sincronizando base de datos...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen">
      <Sidebar 
        activeView={activeView} 
        setActiveView={setActiveView} 
        isCollapsed={isCollapsed} 
        setIsCollapsed={setIsCollapsed} 
      />
      <main 
        className={`flex-1 p-8 overflow-y-auto min-h-screen transition-all duration-300 ${
          isCollapsed ? 'ml-20' : 'ml-64'
        }`}
      >
        <header className="mb-8 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 relative z-20">
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-3xl font-black text-slate-900 tracking-tight">
                {activeView === 'DASHBOARD' && 'Panel de Control'}
                {activeView === 'INVENTORY' && 'Gestión de Inventario'}
                {activeView === 'SALES' && 'Módulo de Ventas'}
                {activeView === 'REPORTS' && 'Reportes y Analítica'}
                {activeView === 'SETTINGS' && 'Configuración'}
              </h1>
              {config.isLinked && (
                <div className="flex flex-col">
                  <button 
                    onClick={() => fetchRemoteData()}
                    disabled={isSyncing}
                    className={`flex items-center gap-1.5 px-3 py-1 bg-green-100 text-green-700 text-[10px] font-bold rounded-full uppercase transition-all ${isSyncing ? 'animate-pulse' : 'hover:bg-green-200'}`}
                  >
                    <i className={`fa-solid ${isSyncing ? 'fa-spinner fa-spin' : 'fa-cloud-check'}`}></i> 
                    {isSyncing ? 'Actualizando' : 'Sincronizado'}
                  </button>
                  {lastSyncTime && !isSyncing && (
                    <span className="text-[9px] text-slate-400 mt-0.5 ml-1">Carga: {lastSyncTime}</span>
                  )}
                </div>
              )}
            </div>
          </div>
          <div className="relative w-full md:w-auto">
            <input
              type="text"
              placeholder="Buscar en Berjitsu..."
              className="pl-12 pr-6 py-3 bg-white border border-slate-200 rounded-2xl shadow-sm focus:ring-4 focus:ring-green-500/10 focus:border-green-500 w-full md:w-96 transition-all"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            <div className="absolute left-4 top-3.5 text-slate-400">
              {isSearching ? <i className="fa-solid fa-spinner fa-spin text-green-500"></i> : <i className="fa-solid fa-magnifying-glass"></i>}
            </div>
          </div>
        </header>

        <div className="relative z-20 fade-in">
          {activeView === 'DASHBOARD' && <DashboardView inventory={inventory} transactions={transactions} />}
          {activeView === 'INVENTORY' && <InventoryView inventory={inventory} filteredIds={filteredIds} onUpdateStock={updateStock} onAddItem={addItem} onDeleteItem={deleteItem} />}
          {activeView === 'SALES' && <SalesView inventory={inventory} onSale={handleSale} />}
          {activeView === 'REPORTS' && <ReportsView transactions={transactions} inventory={inventory} />}
          {activeView === 'SETTINGS' && <SettingsView config={config} onSaveConfig={(newConfig) => {
            setConfig(newConfig);
            if (newConfig.isLinked) fetchRemoteData(newConfig.spreadsheetAppUrl);
          }} />}
        </div>
      </main>
    </div>
  );
};

