import { InventoryItem, Transaction } from "./types";

export type SyncAction = 'UPDATE_INVENTORY' | 'RECORD_SALE';

export const syncWithSheet = async (url: string, action: 'READ' | 'WRITE', payload?: any, syncAction?: SyncAction) => {
  if (!url) return null;

  try {
    if (action === 'READ') {
      const response = await fetch(url, {
        method: 'GET',
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) throw new Error(`HTTP Error: ${response.status}`);
      const data = await response.json();
      return data;
    } else {
      // Estructuramos el cuerpo para que el Apps Script sepa qué hacer
      const body = {
        action: syncAction,
        payload: payload
      };

      // Usamos no-cors para evitar problemas de redirección de Google, 
      // aunque no podamos leer la respuesta, la acción se ejecuta en el servidor.
      await fetch(url, {
        method: 'POST',
        mode: 'no-cors', 
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      return "Sincronizado";
    }
  } catch (error) {
    console.error("Error en SpreadsheetService:", error);
    return null;
  }
};

export const mapSheetDataToInventory = (rows: any[][]): InventoryItem[] => {
  // Verificamos que al menos tengamos cabecera y una fila de datos
  if (!rows || !Array.isArray(rows) || rows.length < 2) return [];

  const headers = rows[0].map((h: any) => String(h).toLowerCase().trim());
  const dataRows = rows.slice(1);

  return dataRows
    .filter(row => row.length >= headers.length) // Ignorar filas incompletas
    .map((row, index) => {
      const getVal = (name: string) => {
        const idx = headers.indexOf(name.toLowerCase());
        return idx > -1 ? row[idx] : null;
      };

      const id = String(getVal('id') || `item-${index}`);

      return {
        id: id,
        sku: String(getVal('sku') || ''),
        name: String(getVal('name') || 'Sin nombre'),
        description: String(getVal('description') || ''),
        category: String(getVal('category') || 'General'),
        price: Number(getVal('price') || 0),
        cost: Number(getVal('cost') || 0),
        stock: Number(getVal('stock') || 0),
        lastUpdated: String(getVal('lastupdated') || new Date().toISOString()),
      };
    });
};

export interface InventoryItem {
  id: string;
  sku: string;
  name: string;
  description: string;
  category: string;
  price: number;
  cost: number;
  stock: number;
  lastUpdated: string;
}

export interface SaleItem {
  itemId: string;
  itemName?: string;
  quantity: number;
  priceAtSale: number;
}

export interface PaymentRecord {
  amount: number;
  timestamp: string;
}

export interface Transaction {
  id: string;
  type: 'SALE' | 'STOCK_IN';
  items: SaleItem[];
  totalAmount: number;
  timestamp: string;
  // Nuevos campos para crédito
  paymentStatus: 'PAID' | 'CREDIT';
  customerName?: string;
  totalPaid: number;
  payments: PaymentRecord[];
}

export type ViewType = 'DASHBOARD' | 'INVENTORY' | 'SALES' | 'REPORTS' | 'SETTINGS';

export interface AppConfig {
  spreadsheetAppUrl: string;
  isLinked: boolean;
}

import React, { useState, useEffect, useCallback } from 'react';
import { InventoryItem, Transaction, ViewType, AppConfig, PaymentRecord } from './types';
import Sidebar from './components/Sidebar';
import DashboardView from './components/DashboardView';
import InventoryView from './components/InventoryView';
import SalesView from './components/SalesView';
import ReportsView from './components/ReportsView';
import SettingsView from './components/SettingsView';
import { semanticSearch } from './geminiService';
import { syncWithSheet, mapSheetDataToInventory, SyncAction } from './spreadsheetService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('DASHBOARD');
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<AppConfig>(() => {
    const saved = localStorage.getItem('berjitsu_config');
    return saved ? JSON.parse(saved) : { spreadsheetAppUrl: '', isLinked: false };
  });

  const [searchQuery, setSearchQuery] = useState('');
  const [filteredIds, setFilteredIds] = useState<string[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isInitialLoad, setIsInitialLoad] = useState(true);

  // Carga inicial
  useEffect(() => {
    const initApp = async () => {
      const savedInv = localStorage.getItem('berjitsu_inventory');
      const savedTransactions = localStorage.getItem('berjitsu_transactions');

      if (savedInv) setInventory(JSON.parse(savedInv));
      if (savedTransactions) setTransactions(JSON.parse(savedTransactions));

      if (config.isLinked && config.spreadsheetAppUrl) {
        setIsSyncing(true);
        try {
          const rows = await syncWithSheet(config.spreadsheetAppUrl, 'READ');
          if (rows && Array.isArray(rows) && rows.length > 1) {
            const mapped = mapSheetDataToInventory(rows);
            if (mapped.length > 0) setInventory(mapped);
          }
        } catch (e) { console.error(e); }
        finally { setIsSyncing(false); }
      }
      setIsInitialLoad(false);
    };
    initApp();
  }, [config.isLinked]);

  // Persistencia Local
  useEffect(() => {
    if (!isInitialLoad) {
      localStorage.setItem('berjitsu_inventory', JSON.stringify(inventory));
      localStorage.setItem('berjitsu_transactions', JSON.stringify(transactions));
      localStorage.setItem('berjitsu_config', JSON.stringify(config));
    }
  }, [inventory, transactions, config, isInitialLoad]);

  const pushToRemote = useCallback((payload: any, syncAction: SyncAction) => {
    if (config.isLinked && config.spreadsheetAppUrl) {
      syncWithSheet(config.spreadsheetAppUrl, 'WRITE', payload, syncAction);
    }
  }, [config.isLinked, config.spreadsheetAppUrl]);

  const handleSale = (
    cartItems: { itemId: string, quantity: number }[], 
    isCredit: boolean = false, 
    customerName: string = '', 
    initialPayment: number = 0
  ) => {
    const updatedInv = inventory.map(item => {
      const soldItem = cartItems.find(si => si.itemId === item.id);
      if (soldItem) {
        return { ...item, stock: Math.max(0, item.stock - soldItem.quantity), lastUpdated: new Date().toISOString() };
      }
      return item;
    });

    const saleItems = cartItems.map(si => {
      const originalItem = inventory.find(i => i.id === si.itemId);
      return {
        itemId: si.itemId,
        itemName: originalItem?.name || 'Producto',
        quantity: si.quantity,
        priceAtSale: originalItem?.price || 0
      };
    });

    const total = saleItems.reduce((acc, curr) => acc + (curr.priceAtSale * curr.quantity), 0);

    const newTransaction: Transaction = {
      id: Math.random().toString(36).substr(2, 6).toUpperCase(),
      type: 'SALE',
      items: saleItems,
      totalAmount: total,
      timestamp: new Date().toISOString(),
      paymentStatus: isCredit ? 'CREDIT' : 'PAID',
      customerName: isCredit ? customerName : undefined,
      totalPaid: isCredit ? initialPayment : total,
      payments: isCredit && initialPayment > 0 ? [{ amount: initialPayment, timestamp: new Date().toISOString() }] : []
    };

    setTransactions(prev => [newTransaction, ...prev]);
    setInventory(updatedInv);
    pushToRemote(newTransaction, 'RECORD_SALE');
    pushToRemote(updatedInv, 'UPDATE_INVENTORY');
  };

  const addPayment = (transactionId: string, amount: number) => {
    const updatedTransactions = transactions.map(t => {
      if (t.id === transactionId) {
        const newTotalPaid = t.totalPaid + amount;
        const newStatus = newTotalPaid >= t.totalAmount ? 'PAID' : 'CREDIT';
        return {
          ...t,
          totalPaid: newTotalPaid,
          paymentStatus: newStatus as 'PAID' | 'CREDIT',
          payments: [...t.payments, { amount, timestamp: new Date().toISOString() }]
        };
      }
      return t;
    });
    setTransactions(updatedTransactions);
    // Sincronizar actualización de la transacción (puedes añadir una acción específica si quieres)
    pushToRemote(updatedTransactions.find(t => t.id === transactionId), 'RECORD_SALE');
  };

  // ... (Resto de funciones addItem, updateStock, etc. se mantienen igual)
  const updateStock = (itemId: string, amount: number, type: 'IN' | 'OUT') => {
    const updated = inventory.map(item => {
      if (item.id === itemId) {
        const newStock = type === 'IN' ? item.stock + amount : Math.max(0, item.stock - amount);
        return { ...item, stock: newStock, lastUpdated: new Date().toISOString() };
      }
      return item;
    });
    setInventory(updated);
    pushToRemote(updated, 'UPDATE_INVENTORY');
  };

  const addItem = (item: Omit<InventoryItem, 'id' | 'lastUpdated'>) => {
    const newItem: InventoryItem = { ...item, id: Math.random().toString(36).substr(2, 9), lastUpdated: new Date().toISOString() };
    const updated = [...inventory, newItem];
    setInventory(updated);
    pushToRemote(updated, 'UPDATE_INVENTORY');
  };

  const deleteItem = (id: string) => {
    const updated = inventory.filter(i => i.id !== id);
    setInventory(updated);
    pushToRemote(updated, 'UPDATE_INVENTORY');
  };

  if (isInitialLoad) return <div className="min-h-screen bg-slate-900 flex items-center justify-center text-white">Cargando Berjitsu...</div>;

  return (
    <div className="flex min-h-screen">
      <Sidebar activeView={activeView} setActiveView={setActiveView} isCollapsed={isCollapsed} setIsCollapsed={setIsCollapsed} />
      <main className={`flex-1 p-8 overflow-y-auto min-h-screen transition-all ${isCollapsed ? 'ml-20' : 'ml-64'}`}>
        <header className="mb-8 flex justify-between items-center">
          <h1 className="text-3xl font-black text-slate-900">{activeView}</h1>
          <div className="flex items-center gap-4">
            <input 
               className="px-4 py-2 border rounded-xl" 
               placeholder="Buscar..." 
               value={searchQuery} 
               onChange={(e) => setSearchQuery(e.target.value)} 
            />
            {isSyncing && <i className="fa-solid fa-spinner fa-spin text-green-500"></i>}
          </div>
        </header>

        <div className="fade-in">
          {activeView === 'DASHBOARD' && <DashboardView inventory={inventory} transactions={transactions} />}
          {activeView === 'INVENTORY' && <InventoryView inventory={inventory} filteredIds={inventory.map(i => i.id)} onUpdateStock={updateStock} onAddItem={addItem} onDeleteItem={deleteItem} />}
          {activeView === 'SALES' && <SalesView inventory={inventory} onSale={handleSale} />}
          {activeView === 'REPORTS' && <ReportsView transactions={transactions} inventory={inventory} onAddPayment={addPayment} />}
          {activeView === 'SETTINGS' && <SettingsView config={config} onSaveConfig={setConfig} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { InventoryItem } from '../types';

interface SalesViewProps {
  inventory: InventoryItem[];
  onSale: (items: { itemId: string, quantity: number }[], isCredit: boolean, customerName: string, initialPayment: number) => void;
}

const SalesView: React.FC<SalesViewProps> = ({ inventory, onSale }) => {
  const [cart, setCart] = useState<{ itemId: string, quantity: number }[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isCredit, setIsCredit] = useState(false);
  const [customerName, setCustomerName] = useState('');
  const [initialPayment, setInitialPayment] = useState(0);

  const filteredItems = inventory.filter(i => 
    (i.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    i.sku.toLowerCase().includes(searchTerm.toLowerCase())) &&
    i.stock > 0
  );

  const addToCart = (itemId: string) => {
    const item = inventory.find(i => String(i.id) === String(itemId));
    if (!item) return;

    setCart(prev => {
      const existing = prev.find(p => p.itemId === itemId);
      if (existing) {
        if (existing.quantity >= item.stock) {
          alert("No hay más stock disponible de este producto.");
          return prev;
        }
        return prev.map(p => p.itemId === itemId ? { ...p, quantity: p.quantity + 1 } : p);
      }
      return [...prev, { itemId, quantity: 1 }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => prev.filter(p => p.itemId !== itemId));
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;
    if (isCredit && !customerName.trim()) {
      alert("Por favor ingrese el nombre del cliente para ventas a crédito.");
      return;
    }

    onSale(cart, isCredit, customerName, initialPayment);
    setCart([]);
    setCustomerName('');
    setInitialPayment(0);
    setIsCredit(false);
    alert('Operación registrada con éxito.');
  };

  const total = cart.reduce((acc, curr) => {
    const item = inventory.find(i => i.id === curr.itemId);
    return acc + (item ? item.price * curr.quantity : 0);
  }, 0);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Seleccionar Productos</h3>
          <input 
            type="text" 
            placeholder="Buscar por nombre o SKU..."
            className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl mb-6 outline-none focus:ring-2 focus:ring-green-500"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            {filteredItems.map(item => (
              <button 
                key={item.id}
                onClick={() => addToCart(item.id)}
                className="flex items-center gap-4 p-4 border border-slate-100 rounded-xl hover:bg-green-50 hover:border-green-200 transition-all text-left group"
              >
                <div className="w-12 h-12 bg-slate-100 rounded-lg flex items-center justify-center text-slate-400 group-hover:bg-green-100 group-hover:text-green-600">
                  <i className="fa-solid fa-plus"></i>
                </div>
                <div className="flex-1">
                  <p className="font-bold text-slate-800 leading-tight">{item.name}</p>
                  <p className="text-xs text-slate-500">Stock: {item.stock}</p>
                </div>
                <p className="font-bold text-green-600">${item.price}</p>
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="lg:col-span-1">
        <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100 sticky top-8">
          <h3 className="text-xl font-bold text-slate-800 mb-6">Resumen</h3>

          <div className="space-y-4 mb-6 max-h-60 overflow-y-auto pr-2">
            {cart.map(c => {
              const item = inventory.find(i => i.id === c.itemId);
              return item ? (
                <div key={c.itemId} className="flex justify-between items-center bg-slate-50 p-3 rounded-xl">
                  <div>
                    <p className="font-bold text-sm">{item.name}</p>
                    <p className="text-xs text-slate-500">Cant: {c.quantity}</p>
                  </div>
                  <div className="flex items-center gap-3">
                    <span className="font-bold text-slate-700">${(item.price * c.quantity).toFixed(2)}</span>
                    <button onClick={() => removeFromCart(c.itemId)} className="text-red-400 hover:text-red-600">
                      <i className="fa-solid fa-trash-can text-sm"></i>
                    </button>
                  </div>
                </div>
              ) : null;
            })}
          </div>

          <div className="space-y-4 border-t pt-6">
            <div className="flex bg-slate-100 p-1 rounded-xl">
              <button 
                onClick={() => setIsCredit(false)}
                className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${!isCredit ? 'bg-white shadow-sm text-green-600' : 'text-slate-500'}`}
              >Contado</button>
              <button 
                onClick={() => setIsCredit(true)}
                className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${isCredit ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}
              >Crédito</button>
            </div>

            {isCredit && (
              <div className="space-y-3 animate-in slide-in-from-top-2">
                <input 
                  type="text" 
                  placeholder="Nombre del Cliente"
                  className="w-full px-4 py-2 bg-blue-50 border border-blue-100 rounded-xl text-sm outline-none focus:ring-2 focus:ring-blue-500"
                  value={customerName}
                  onChange={e => setCustomerName(e.target.value)}
                />
                <div className="flex items-center gap-2">
                  <label className="text-xs font-bold text-slate-500 whitespace-nowrap">Abono Inicial $</label>
                  <input 
                    type="number" 
                    className="w-full px-4 py-2 bg-blue-50 border border-blue-100 rounded-xl text-sm"
                    value={initialPayment}
                    onChange={e => setInitialPayment(Number(e.target.value))}
                  />
                </div>
              </div>
            )}

            <div className="flex justify-between items-center text-2xl font-black text-slate-900 pt-2">
              <span>Total</span>
              <span>${total.toFixed(2)}</span>
            </div>

            {isCredit && (
              <div className="flex justify-between text-sm text-red-500 font-bold">
                <span>Saldo Pendiente</span>
                <span>${(total - initialPayment).toFixed(2)}</span>
              </div>
            )}

            <button 
              disabled={cart.length === 0}
              onClick={handleCheckout}
              className={`w-full py-4 rounded-2xl font-black text-white shadow-lg transition-all ${isCredit ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 'bg-green-600 hover:bg-green-700 shadow-green-200'}`}
            >
              Confirmar {isCredit ? 'Crédito' : 'Venta'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

