export type SyncAction = 'UPDATE_INVENTORY' | 'RECORD_SALE';

export const syncWithSheet = async (url: string, action: 'READ' | 'WRITE', payload?: any, syncAction?: SyncAction) => {
  if (!url) return null;

  try {
    if (action === 'READ') {
      const response = await fetch(url, {
        method: 'GET',
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) throw new Error(`HTTP Error: ${response.status}`);
      const data = await response.json();
      return data;
    } else {
      const body = {
        action: syncAction,
        payload: payload
      };

      await fetch(url, {
        method: 'POST',
        mode: 'no-cors', 
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      return "Sincronizado";
    }
  } catch (error) {
    console.error("Error en SpreadsheetService:", error);
    return null;
  }
};

// Función auxiliar para convertir a número de forma segura
const safeNumber = (val: any): number => {
  if (val === null || val === undefined || val === '') return 0;
  // Si es string, quitar comas de miles y espacios
  if (typeof val === 'string') {
    const clean = val.replace(/[^0-9.-]/g, '');
    const num = parseFloat(clean);
    return isNaN(num) ? 0 : num;
  }
  return isNaN(Number(val)) ? 0 : Number(val);
};

export const mapSheetDataToInventory = (rows: any[][]): InventoryItem[] => {
  if (!rows || !Array.isArray(rows) || rows.length < 2) return [];

  const headers = rows[0].map((h: any) => String(h).toLowerCase().trim());
  const dataRows = rows.slice(1);

  return dataRows
    .filter(row => row.length > 0 && row.some(cell => cell !== ''))
    .map((row, index) => {
      const getVal = (name: string) => {
        const idx = headers.indexOf(name.toLowerCase());
        return idx > -1 ? row[idx] : null;
      };

      // Limpiamos el ID de posibles espacios
      const rawId = getVal('id');
      const id = rawId ? String(rawId).trim() : `item-${index}`;

      return {
        id: id,
        sku: String(getVal('sku') || '').trim(),
        name: String(getVal('name') || 'Sin nombre').trim(),
        description: String(getVal('description') || '').trim(),
        category: String(getVal('category') || 'General').trim(),
        price: safeNumber(getVal('price')),
        cost: safeNumber(getVal('cost')),
        stock: safeNumber(getVal('stock')),
        lastUpdated: String(getVal('lastupdated') || new Date().toISOString()),
      };
    });
};

import React, { useState, useMemo } from 'react';
import { InventoryItem } from '../types';

interface SalesViewProps {
  inventory: InventoryItem[];
  onSale: (items: { itemId: string, quantity: number }[], isCredit: boolean, customerName: string, initialPayment: number) => void;
}

const SalesView: React.FC<SalesViewProps> = ({ inventory, onSale }) => {
  const [cart, setCart] = useState<{ itemId: string, quantity: number }[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isCredit, setIsCredit] = useState(false);
  const [customerName, setCustomerName] = useState('');
  const [initialPayment, setInitialPayment] = useState(0);

  // Aseguramos que solo mostramos items con stock real > 0
  const filteredItems = useMemo(() => {
    return inventory.filter(i => {
      const matchesSearch = 
        i.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        i.sku.toLowerCase().includes(searchTerm.toLowerCase()) ||
        i.category.toLowerCase().includes(searchTerm.toLowerCase());

      const hasStock = Number(i.stock) > 0;
      return matchesSearch && hasStock;
    });
  }, [inventory, searchTerm]);

  const addToCart = (itemId: string) => {
    // Buscamos el item comparando IDs como strings limpios
    const item = inventory.find(i => String(i.id).trim() === String(itemId).trim());

    if (!item) {
      console.error("Item no encontrado:", itemId);
      return;
    }

    const itemStock = Number(item.stock);

    setCart(prev => {
      const existing = prev.find(p => String(p.itemId).trim() === String(itemId).trim());

      if (existing) {
        if (Number(existing.quantity) >= itemStock) {
          alert(`No puedes agregar más. El stock disponible es de ${itemStock} unidades.`);
          return prev;
        }
        return prev.map(p => 
          String(p.itemId).trim() === String(itemId).trim() 
            ? { ...p, quantity: p.quantity + 1 } 
            : p
        );
      }

      // Primera vez que se agrega
      return [...prev, { itemId: String(itemId).trim(), quantity: 1 }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => prev.filter(p => String(p.itemId).trim() !== String(itemId).trim()));
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;
    if (isCredit && !customerName.trim()) {
      alert("Por favor ingrese el nombre del cliente para ventas a crédito.");
      return;
    }

    onSale(cart, isCredit, customerName, initialPayment);
    setCart([]);
    setCustomerName('');
    setInitialPayment(0);
    setIsCredit(false);
  };

  const total = useMemo(() => {
    return cart.reduce((acc, curr) => {
      const item = inventory.find(i => String(i.id).trim() === String(curr.itemId).trim());
      return acc + (item ? Number(item.price) * curr.quantity : 0);
    }, 0);
  }, [cart, inventory]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-bold text-slate-800">Seleccionar Productos</h3>
            <span className="text-xs font-bold text-slate-400 uppercase bg-slate-100 px-3 py-1 rounded-full">
              {filteredItems.length} disponibles
            </span>
          </div>

          <div className="relative mb-6">
            <input 
              type="text" 
              placeholder="Escribe nombre, categoría o SKU..."
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-green-500 transition-all"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
            <i className="fa-solid fa-magnifying-glass absolute left-4 top-4 text-slate-400"></i>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 max-h-[600px] overflow-y-auto pr-2">
            {filteredItems.map(item => (
              <button 
                key={item.id}
                onClick={() => addToCart(item.id)}
                className="flex items-center gap-4 p-4 border border-slate-100 rounded-2xl hover:bg-green-50 hover:border-green-200 transition-all text-left group active:scale-[0.98]"
              >
                <div className="w-12 h-12 bg-white border border-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:text-green-600 group-hover:border-green-100 shadow-sm transition-all">
                  <i className="fa-solid fa-cart-plus text-lg"></i>
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-bold text-slate-800 leading-tight truncate">{item.name}</p>
                  <p className="text-[10px] text-slate-500 font-medium uppercase tracking-tighter">{item.category} • SKU: {item.sku}</p>
                  <div className="flex items-center gap-2 mt-1">
                    <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${Number(item.stock) <= 5 ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>
                      {item.stock} en stock
                    </span>
                  </div>
                </div>
                <div className="text-right">
                  <p className="font-black text-green-600 text-lg">${Number(item.price).toFixed(2)}</p>
                </div>
              </button>
            ))}
            {filteredItems.length === 0 && (
              <div className="col-span-full py-12 text-center text-slate-400">
                <i className="fa-solid fa-box-open text-4xl mb-3 opacity-20"></i>
                <p>No hay productos con stock que coincidan.</p>
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="lg:col-span-1">
        <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100 sticky top-8">
          <div className="flex items-center gap-3 mb-6">
            <div className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center">
              <i className="fa-solid fa-receipt"></i>
            </div>
            <h3 className="text-xl font-bold text-slate-800">Resumen</h3>
          </div>

          <div className="space-y-3 mb-6 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {cart.map(c => {
              const item = inventory.find(i => String(i.id).trim() === String(c.itemId).trim());
              return item ? (
                <div key={c.itemId} className="flex justify-between items-center bg-slate-50 p-3 rounded-2xl border border-slate-100 animate-in fade-in slide-in-from-right-2">
                  <div className="min-w-0 flex-1">
