interface SettingsViewProps {
  config: AppConfig;
  onSaveConfig: (config: AppConfig) => void;
}

const SettingsView: React.FC<SettingsViewProps> = ({ config, onSaveConfig }) => {
  const [url, setUrl] = useState(config.spreadsheetAppUrl);
  const [showCode, setShowCode] = useState(false);

  const scriptCode = `function doGet(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheet = ss.getSheetByName("Inventario") || ss.getSheets()[0];
  var data = sheet.getDataRange().getValues();
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  var data = JSON.parse(e.postData.contents);
  var ss = SpreadsheetApp.getActiveSpreadsheet();

  if (data.action === "UPDATE_INVENTORY") {
    var sheet = ss.getSheetByName("Inventario") || ss.insertSheet("Inventario");
    sheet.clear();
    var headers = ["id", "sku", "name", "description", "category", "price", "cost", "stock", "lastUpdated"];
    sheet.appendRow(headers);
    data.payload.forEach(function(item) {
      sheet.appendRow([item.id, item.sku, item.name, item.description, item.category, item.price, item.cost, item.stock, item.lastUpdated]);
    });
  } else if (data.action === "RECORD_SALE") {
    var sheet = ss.getSheetByName("Ventas") || ss.insertSheet("Ventas");
    if (sheet.getLastRow() === 0) {
      sheet.appendRow(["ID Transaccion", "Timestamp", "Cliente", "Estado", "Total", "Pagado", "Articulos", "Detalle"]);
    }

    // Generar resumen legible de artículos
    var itemsSummary = data.payload.items.map(function(item) {
      return item.itemName + " (x" + item.quantity + ")";
    }).join(", ");

    sheet.appendRow([
      data.payload.id, 
      data.payload.timestamp, 
      data.payload.customerName || "Contado", 
      data.payload.paymentStatus, 
      data.payload.totalAmount, 
      data.payload.totalPaid, 
      itemsSummary,
      JSON.stringify(data.payload.items)
    ]);
  }
  return ContentService.createTextOutput("OK");
}`;

  const handleSave = () => {
    onSaveConfig({
      spreadsheetAppUrl: url,
      isLinked: url.length > 5
    });
    alert("Configuración guardada correctamente.");
  };

  return (
    <div className="max-w-4xl space-y-8 pb-20">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        <div className="space-y-6">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
            <div className="flex items-center gap-4 mb-6">
              <div className="w-12 h-12 bg-green-100 text-green-600 rounded-2xl flex items-center justify-center">
                <i className="fa-solid fa-link text-xl"></i>
              </div>
              <div>
                <h3 className="text-xl font-bold text-slate-800">Conectar Base de Datos</h3>
                <p className="text-slate-500 text-sm">Sincroniza con Google Sheets.</p>
              </div>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-sm font-semibold text-slate-700">URL de Apps Script</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-green-500 text-sm"
                  placeholder="https://script.google.com/macros/s/.../exec"
                  value={url}
                  onChange={(e) => setUrl(e.target.value)}
                />
              </div>

              <button 
                onClick={handleSave}
                className="w-full bg-slate-900 hover:bg-slate-800 text-white py-4 rounded-2xl font-bold transition-all flex items-center justify-center gap-2"
              >
                <i className="fa-solid fa-cloud-arrow-up"></i> Guardar Configuración
              </button>
            </div>
          </div>
        </div>

        <div className="bg-slate-900 text-white p-8 rounded-3xl shadow-xl flex flex-col">
          <h3 className="text-xl font-bold mb-6 flex items-center gap-3">
            <i className="fa-solid fa-graduation-cap text-green-500"></i> 
            Guía Técnica
          </h3>
          <p className="text-sm text-slate-300 mb-4">Si has actualizado la App, recuerda actualizar también el código en tu Google Apps Script para que los nuevos campos de crédito y artículos se guarden correctamente.</p>
          <button 
            onClick={() => setShowCode(true)}
            className="w-full bg-green-600 hover:bg-green-500 text-white py-3 rounded-xl font-bold text-sm transition-colors mt-auto"
          >
            <i className="fa-solid fa-code mr-2"></i> Copiar Código Actualizado
          </button>
        </div>
      </div>

      {showCode && (
        <div className="fixed inset-0 z-[100] bg-slate-900/90 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-slate-800 w-full max-w-3xl rounded-3xl overflow-hidden shadow-2xl border border-slate-700 flex flex-col max-h-[90vh]">
            <div className="p-6 border-b border-slate-700 flex justify-between items-center bg-slate-800/50">
              <h4 className="text-white font-bold">Nuevo Código de Servidor</h4>
