import React, { useState, useMemo } from 'react';
import { InventoryItem } from '../types';

interface SalesViewProps {
  inventory: InventoryItem[];
  onSale: (items: { itemId: string, quantity: number }[], isCredit: boolean, customerName: string, initialPayment: number) => void;
}

const SalesView: React.FC<SalesViewProps> = ({ inventory, onSale }) => {
  const [cart, setCart] = useState<{ itemId: string, quantity: number }[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isCredit, setIsCredit] = useState(false);
  const [customerName, setCustomerName] = useState('');
  const [initialPayment, setInitialPayment] = useState(0);

  // Aseguramos que solo mostramos items con stock real > 0
  const filteredItems = useMemo(() => {
    return inventory.filter(i => {
      const matchesSearch = 
        i.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        i.sku.toLowerCase().includes(searchTerm.toLowerCase()) ||
        i.category.toLowerCase().includes(searchTerm.toLowerCase());

      const hasStock = Number(i.stock) > 0;
      return matchesSearch && hasStock;
    });
  }, [inventory, searchTerm]);

  const addToCart = (itemId: string) => {
    // Buscamos el item comparando IDs como strings limpios
    const item = inventory.find(i => String(i.id).trim() === String(itemId).trim());

    if (!item) {
      console.error("Item no encontrado:", itemId);
      return;
    }

    const itemStock = Number(item.stock);

    setCart(prev => {
      const existing = prev.find(p => String(p.itemId).trim() === String(itemId).trim());

      if (existing) {
        if (Number(existing.quantity) >= itemStock) {
          alert(`No puedes agregar más. El stock disponible es de ${itemStock} unidades.`);
          return prev;
        }
        return prev.map(p => 
          String(p.itemId).trim() === String(itemId).trim() 
            ? { ...p, quantity: p.quantity + 1 } 
            : p
        );
      }

      // Primera vez que se agrega
      return [...prev, { itemId: String(itemId).trim(), quantity: 1 }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => prev.filter(p => String(p.itemId).trim() !== String(itemId).trim()));
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;
    if (isCredit && !customerName.trim()) {
      alert("Por favor ingrese el nombre del cliente para ventas a crédito.");
      return;
    }

    onSale(cart, isCredit, customerName, initialPayment);
    setCart([]);
    setCustomerName('');
    setInitialPayment(0);
    setIsCredit(false);
  };

  const total = useMemo(() => {
    return cart.reduce((acc, curr) => {
      const item = inventory.find(i => String(i.id).trim() === String(curr.itemId).trim());
      return acc + (item ? Number(item.price) * curr.quantity : 0);
    }, 0);
  }, [cart, inventory]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-bold text-slate-800">Seleccionar Productos</h3>
            <span className="text-xs font-bold text-slate-400 uppercase bg-slate-100 px-3 py-1 rounded-full">
              {filteredItems.length} disponibles
            </span>
          </div>

          <div className="relative mb-6">
            <input 
              type="text" 
              placeholder="Escribe nombre, categoría o SKU..."
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-green-500 transition-all"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
            <i className="fa-solid fa-magnifying-glass absolute left-4 top-4 text-slate-400"></i>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 max-h-[600px] overflow-y-auto pr-2">
            {filteredItems.map(item => (
              <button 
                key={item.id}
                onClick={() => addToCart(item.id)}
                className="flex items-center gap-4 p-4 border border-slate-100 rounded-2xl hover:bg-green-50 hover:border-green-200 transition-all text-left group active:scale-[0.98]"
              >
                <div className="w-12 h-12 bg-white border border-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:text-green-600 group-hover:border-green-100 shadow-sm transition-all">
                  <i className="fa-solid fa-cart-plus text-lg"></i>
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-bold text-slate-800 leading-tight">{item.name}</p>
                  <p className="text-[10px] text-slate-500 font-medium uppercase tracking-tighter mt-1">{item.category} • SKU: {item.sku}</p>
                  <div className="flex items-center gap-2 mt-1">
                    <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${Number(item.stock) <= 5 ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>
                      {item.stock} en stock
                    </span>
                  </div>
                </div>
                <div className="text-right">
                  <p className="font-black text-green-600 text-lg">${Number(item.price).toFixed(2)}</p>
                </div>
              </button>
            ))}
            {filteredItems.length === 0 && (
              <div className="col-span-full py-12 text-center text-slate-400">
                <i className="fa-solid fa-box-open text-4xl mb-3 opacity-20"></i>
                <p>No hay productos con stock que coincidan.</p>
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="lg:col-span-1">
        <div className="bg-white p-6 rounded-3xl shadow-xl border border-slate-100 sticky top-8">
          <div className="flex items-center gap-3 mb-6">
            <div className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center">
              <i className="fa-solid fa-receipt"></i>
            </div>
            <h3 className="text-xl font-bold text-slate-800">Resumen</h3>
          </div>

          <div className="space-y-3 mb-6 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
            {cart.map(c => {
              const item = inventory.find(i => String(i.id).trim() === String(c.itemId).trim());
              return item ? (
                <div key={c.itemId} className="flex justify-between items-center bg-slate-50 p-3 rounded-2xl border border-slate-100 animate-in fade-in slide-in-from-right-2">
                  <div className="min-w-0 flex-1">
                    <p className="font-bold text-sm leading-tight">{item.name}</p>
                    <div className="flex items-center gap-2 mt-1">
                      <span className="text-[10px] font-bold text-slate-400">Cant: {c.quantity}</span>
                      <span className="text-[10px] font-bold text-green-600">x ${Number(item.price).toFixed(2)}</span>
                    </div>
                  </div>
                  <div className="flex items-center gap-3 ml-4">
                    <span className="font-black text-slate-700 text-sm whitespace-nowrap">${(Number(item.price) * c.quantity).toFixed(2)}</span>
                    <button 
                      onClick={() => removeFromCart(c.itemId)} 
                      className="w-8 h-8 rounded-lg text-red-400 hover:bg-red-50 hover:text-red-600 transition-colors flex items-center justify-center"
                    >
                      <i className="fa-solid fa-xmark text-sm"></i>
                    </button>
                  </div>
                </div>
              ) : null;
            })}
            {cart.length === 0 && (
               <div className="py-8 text-center text-slate-300 italic text-sm">
                 El carrito está vacío
               </div>
            )}
          </div>

          <div className="space-y-4 border-t border-slate-100 pt-6">
            <div className="flex bg-slate-100 p-1 rounded-2xl">
              <button 
                onClick={() => setIsCredit(false)}
                className={`flex-1 py-2.5 rounded-xl text-xs font-black transition-all uppercase tracking-widest ${!isCredit ? 'bg-white shadow-sm text-green-600' : 'text-slate-500'}`}
              >Contado</button>
              <button 
                onClick={() => setIsCredit(true)}
                className={`flex-1 py-2.5 rounded-xl text-xs font-black transition-all uppercase tracking-widest ${isCredit ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}
              >Crédito</button>
            </div>

            {isCredit && (
              <div className="space-y-3 animate-in slide-in-from-top-4 duration-300">
                <div className="relative">
                  <input 
                    type="text" 
                    placeholder="Nombre del Cliente"
                    className="w-full pl-10 pr-4 py-3 bg-blue-50 border border-blue-100 rounded-xl text-sm outline-none focus:ring-2 focus:ring-blue-500"
                    value={customerName}
                    onChange={e => setCustomerName(e.target.value)}
                  />
                  <i className="fa-solid fa-user absolute left-3.5 top-3.5 text-blue-300"></i>
                </div>
                <div className="bg-blue-50 p-4 rounded-xl border border-blue-100">
                  <label className="block text-[10px] font-black text-blue-400 uppercase mb-2">Abono Inicial</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      className="w-full pl-8 pr-4 py-2 bg-white border border-blue-100 rounded-lg text-sm font-bold outline-none"
                      value={initialPayment || ''}
                      onChange={e => setInitialPayment(Number(e.target.value))}
                      placeholder="0.00"
                    />
                    <span className="absolute left-3 top-2 text-blue-300 font-bold">$</span>
                  </div>
                </div>
              </div>
            )}

            <div className="flex justify-between items-center pt-2">
              <span className="text-slate-400 font-bold text-sm uppercase">Total a pagar</span>
              <span className="text-3xl font-black text-slate-900 tracking-tighter">${total.toFixed(2)}</span>
            </div>

            {isCredit && (
              <div className="flex justify-between items-center px-4 py-2 bg-red-50 rounded-xl text-red-600">
                <span className="text-[10px] font-black uppercase">Saldo Pendiente</span>
                <span className="font-black">${(total - initialPayment).toFixed(2)}</span>
              </div>
            )}

            <button 
              disabled={cart.length === 0}
              onClick={handleCheckout}
              className={`w-full py-5 rounded-2xl font-black text-white shadow-xl transition-all active:scale-[0.97] disabled:opacity-50 disabled:grayscale ${
                isCredit 
                  ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' 
                  : 'bg-green-600 hover:bg-green-700 shadow-green-200'
              }`}
            >
              <i className={`fa-solid ${isCredit ? 'fa-hand-holding-dollar' : 'fa-check-double'} mr-2`}></i>
              CONFIRMAR {isCredit ? 'CRÉDITO' : 'VENTA'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SalesView;

