                <i className="fa-solid fa-check-circle"></i>
             </div>
             <p className="text-slate-400 font-black text-lg">No hay cuentas pendientes por cobrar.</p>
             <p className="text-slate-300 text-sm mt-2 font-medium">¡Gran trabajo manteniendo las cuentas al día!</p>
          </div>
        )}
      </div>

      {selectedDebt && (
        <div className="fixed inset-0 z-[110] bg-slate-900/90 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in duration-200 overflow-hidden relative">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-black text-slate-900 tracking-tighter">REGISTRAR PAGO</h3>
                <button onClick={() => setSelectedDebt(null)} className="w-10 h-10 flex items-center justify-center rounded-full bg-slate-100 text-slate-400 hover:text-red-500 transition-all">
                  <i className="fa-solid fa-xmark"></i>
                </button>
             </div>

             <div className="bg-slate-900 text-white p-6 rounded-[2rem] mb-6 relative overflow-hidden">
                <p className="text-[10px] text-white/40 font-black uppercase tracking-widest mb-1">Deuda de Cliente</p>
                <p className="text-xl font-black mb-4 truncate">{selectedDebt.customerName}</p>
                <div className="flex justify-between items-center border-t border-white/10 pt-4 font-black">
                  <span className="text-xs text-white/50">SALDO PENDIENTE</span>
                  <span className="text-2xl text-green-400">${(selectedDebt.totalAmount - selectedDebt.totalPaid).toFixed(2)}</span>
                </div>
                <i className="fa-solid fa-piggy-bank absolute -right-4 -bottom-4 text-6xl opacity-10"></i>
             </div>

             <div className="space-y-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">Monto del Abono</label>
                  <div className="relative">
                    <span className="absolute left-6 top-5 font-black text-slate-400 text-xl">$</span>
                    <input 
                      type="number" 
                      className="w-full pl-12 pr-6 py-5 bg-slate-50 border border-slate-200 rounded-3xl text-2xl font-black focus:ring-4 focus:ring-green-500/10 focus:border-green-500 outline-none transition-all"
                      placeholder="0.00"
                      autoFocus
                      value={abonoAmount || ''}
                      onChange={e => setAbonoAmount(Number(e.target.value))}
                    />
                  </div>
                </div>

                <button 
                  onClick={handleRegisterAbono}
                  className="w-full bg-green-600 hover:bg-green-700 text-white py-5 rounded-3xl font-black shadow-xl shadow-green-100 transition-all flex items-center justify-center gap-2 text-sm"
                >
                  <i className="fa-solid fa-check-double"></i> CONFIRMAR ABONO
                </button>
                <button 
                  onClick={() => setSelectedDebt(null)}
                  className="w-full text-slate-400 py-2 font-bold text-xs hover:text-slate-600 transition-colors"
                >
                  CANCELAR OPERACIÓN
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CreditsView;

import React, { useState, useMemo } from 'react';
import { InventoryItem, Client } from '../types';

interface SalesViewProps {
  inventory: InventoryItem[];
  clients: Client[];
  onSale: (items: { itemId: string, quantity: number }[], isCredit: boolean, customerId: string, initialPayment: number) => void;
}

const SalesView: React.FC<SalesViewProps> = ({ inventory, clients, onSale }) => {
  const [cart, setCart] = useState<{ itemId: string, quantity: number }[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isCredit, setIsCredit] = useState(false);
  const [selectedClientId, setSelectedClientId] = useState('');
  const [initialPayment, setInitialPayment] = useState(0);

  const filteredItems = useMemo(() => {
    return inventory.filter(i => {
      const matchesSearch = 
        i.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        i.sku.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesSearch && Number(i.stock) > 0;
    });
  }, [inventory, searchTerm]);

  const addToCart = (itemId: string) => {
    const item = inventory.find(i => String(i.id).trim() === String(itemId).trim());
    if (!item) return;

    setCart(prev => {
      const existing = prev.find(p => String(p.itemId).trim() === String(itemId).trim());
      if (existing) {
        if (existing.quantity >= Number(item.stock)) {
          alert("No hay suficiente stock.");
          return prev;
        }
        return prev.map(p => p.itemId === itemId ? { ...p, quantity: p.quantity + 1 } : p);
      }
      return [...prev, { itemId: itemId, quantity: 1 }];
    });
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;
    if (isCredit && !selectedClientId) {
      alert("Debes seleccionar un cliente registrado para ventas a crédito.");
      return;
    }

    onSale(cart, isCredit, selectedClientId, initialPayment);
    setCart([]);
    setSelectedClientId('');
    setInitialPayment(0);
    setIsCredit(false);
  };

  const total = useMemo(() => {
    return cart.reduce((acc, curr) => {
      const item = inventory.find(i => String(i.id).trim() === String(curr.itemId).trim());
      return acc + (item ? Number(item.price) * curr.quantity : 0);
    }, 0);
  }, [cart, inventory]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <div className="relative mb-6">
            <input 
              type="text" 
              placeholder="Buscar producto por nombre o SKU..."
              className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-green-500 transition-all font-medium"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
            <i className="fa-solid fa-magnifying-glass absolute left-4 top-5 text-slate-400"></i>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
            {filteredItems.map(item => (
              <button 
                key={item.id}
                onClick={() => addToCart(item.id)}
                className="flex items-center gap-4 p-4 border border-slate-100 rounded-2xl hover:bg-green-50 hover:border-green-200 transition-all text-left group active:scale-[0.98]"
              >
                <div className="w-12 h-12 bg-white border border-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:text-green-600 transition-all">
                  <i className="fa-solid fa-cart-plus text-lg"></i>
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-bold text-slate-800 leading-tight mb-1">{item.name}</p>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{item.stock} disponibles</p>
                </div>
                <p className="font-black text-green-600 text-lg">${Number(item.price).toFixed(2)}</p>
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="lg:col-span-1">
        <div className="bg-white p-6 rounded-[2.5rem] shadow-xl border border-slate-100 sticky top-8">
          <h3 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-2">
            <i className="fa-solid fa-receipt text-green-600"></i> RESUMEN
          </h3>

          <div className="space-y-3 mb-6 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
            {cart.map(c => {
              const item = inventory.find(i => i.id === c.itemId);
              return item ? (
                <div key={c.itemId} className="flex justify-between items-center bg-slate-50 p-3 rounded-2xl">
                  <div className="min-w-0 flex-1">
                    <p className="font-bold text-sm leading-tight truncate">{item.name}</p>
                    <p className="text-[10px] font-bold text-slate-400">{c.quantity} un. x ${item.price.toFixed(2)}</p>
                  </div>
                  <span className="font-black text-slate-700 text-sm ml-4">${(item.price * c.quantity).toFixed(2)}</span>
                </div>
              ) : null;
            })}
          </div>

          <div className="space-y-4 border-t border-slate-100 pt-6">
            <div className="flex bg-slate-100 p-1 rounded-2xl mb-4">
              <button onClick={() => setIsCredit(false)} className={`flex-1 py-2 rounded-xl text-xs font-black transition-all ${!isCredit ? 'bg-white shadow-sm text-green-600' : 'text-slate-500'}`}>CONTADO</button>
              <button onClick={() => setIsCredit(true)} className={`flex-1 py-2 rounded-xl text-xs font-black transition-all ${isCredit ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>CRÉDITO</button>
            </div>

            <div className="space-y-3">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Seleccionar Cliente</label>
              <select 
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none focus:ring-2 focus:ring-green-500"
                value={selectedClientId}
                onChange={e => setSelectedClientId(e.target.value)}
              >
                <option value="">Cliente Ocasional / General</option>
                {clients.map(c => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>
            </div>

            {isCredit && (
              <div className="bg-blue-50 p-4 rounded-2xl animate-in slide-in-from-top-4">
                <label className="block text-[10px] font-black text-blue-400 uppercase mb-2">Abono Inicial</label>
                <input 
                  type="number" 
                  className="w-full px-4 py-2 bg-white border border-blue-100 rounded-xl text-lg font-black outline-none"
                  value={initialPayment || ''}
                  onChange={e => setInitialPayment(Number(e.target.value))}
                  placeholder="0.00"
                />
              </div>
            )}

            <div className="flex justify-between items-center py-2">
              <span className="text-slate-400 font-bold text-sm">TOTAL</span>
              <span className="text-3xl font-black text-slate-900 tracking-tighter">${total.toFixed(2)}</span>
            </div>

            <button 
              disabled={cart.length === 0}
              onClick={handleCheckout}
              className={`w-full py-5 rounded-2xl font-black text-white shadow-xl transition-all active:scale-[0.97] ${isCredit ? 'bg-blue-600' : 'bg-green-600'}`}
            >
              CONFIRMAR {isCredit ? 'CRÉDITO' : 'VENTA'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SalesView;

