  const [stockInputs, setStockInputs] = useState<Record<string, number>>({});

  const [newItem, setNewItem] = useState({
    sku: '',
    name: '',
    description: '',
    category: '',
    price: 0,
    cost: 0,
    stock: 0
  });

  const filteredItems = useMemo(() => {
    const term = searchTerm.toLowerCase().trim();
    if (!term) return inventory;

    return inventory.filter(i => {
      const name = (i.name || '').toLowerCase();
      const sku = (i.sku || '').toLowerCase();
      const category = (i.category || '').toLowerCase();
      return name.includes(term) || sku.includes(term) || category.includes(term);
    });
  }, [inventory, searchTerm]);

  const handleQuickDesc = async () => {
    if (!newItem.name) return;
    setIsGenerating(true);
    const desc = await generateItemDescription(newItem.name);
    setNewItem(prev => ({ ...prev, description: desc }));
    setIsGenerating(false);
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddItem(newItem);
    setNewItem({ sku: '', name: '', description: '', category: '', price: 0, cost: 0, stock: 0 });
    setShowAddModal(false);
  };

  const handleStockUpdate = (id: string) => {
    const amount = stockInputs[id];
    if (!amount || amount <= 0) {
      alert("Por favor digite una cantidad válida para ingresar.");
      return;
    }
    onUpdateStock(id, amount);
    setStockInputs(prev => ({ ...prev, [id]: 0 }));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">Gestión de Inventario</h3>
