import React, { useState } from 'react';
import { Transaction, InventoryItem } from '../types';

interface ReportsViewProps {
  transactions: Transaction[];
  inventory: InventoryItem[];
  onAddPayment: (transactionId: string, amount: number) => void;
}

const ReportsView: React.FC<ReportsViewProps> = ({ transactions, inventory, onAddPayment }) => {
  const [tab, setTab] = useState<'HISTORY' | 'DEBTS'>('HISTORY');
  const [selectedDebt, setSelectedDebt] = useState<Transaction | null>(null);
  const [abonoAmount, setAbonoAmount] = useState(0);

  const debts = transactions.filter(t => t.paymentStatus === 'CREDIT');

  const handleRegisterAbono = () => {
    if (!selectedDebt || abonoAmount <= 0) return;
    onAddPayment(selectedDebt.id, abonoAmount);
    setAbonoAmount(0);
    setSelectedDebt(null);
    alert("Abono registrado correctamente.");
  };

  return (
    <div className="space-y-6">
      <div className="flex gap-4 border-b pb-4">
        <button 
          onClick={() => setTab('HISTORY')}
          className={`px-6 py-2 rounded-xl font-bold transition-all ${tab === 'HISTORY' ? 'bg-slate-900 text-white' : 'text-slate-500 hover:bg-slate-100'}`}
        >Historial General</button>
        <button 
          onClick={() => setTab('DEBTS')}
          className={`px-6 py-2 rounded-xl font-bold transition-all ${tab === 'DEBTS' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:bg-slate-100'}`}
        >Cuentas por Cobrar ({debts.length})</button>
      </div>

      {tab === 'HISTORY' ? (
        <div className="bg-white rounded-2xl shadow-sm border overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">ID / Fecha</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Cliente</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Tipo</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Total</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Estado</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {transactions.map(t => (
                <tr key={t.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-800">#{t.id}</div>
                    <div className="text-[10px] text-slate-400">{new Date(t.timestamp).toLocaleString()}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600 text-sm font-medium">{t.customerName || 'Venta Mostrador'}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${t.paymentStatus === 'PAID' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'}`}>
                      {t.paymentStatus}
                    </span>
                  </td>
                  <td className="px-6 py-4 font-bold text-slate-800">₡{t.totalAmount.toLocaleString()}</td>
                  <td className="px-6 py-4">
                    {t.paymentStatus === 'PAID' ? (
                      <span className="text-green-500 text-xs font-bold">Cobrado</span>
                    ) : (
                      <span className="text-amber-500 text-xs font-bold">Saldo: ₡{(t.totalAmount - t.totalPaid).toLocaleString()}</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {debts.map(debt => (
            <div key={debt.id} className="bg-white p-6 rounded-3xl border border-blue-100 shadow-sm hover:shadow-md transition-all">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h4 className="font-black text-slate-900 text-lg uppercase">{debt.customerName}</h4>
                  <p className="text-xs text-slate-400">Venta #{debt.id}</p>
                </div>
                <div className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-[10px] font-bold">PENDIENTE</div>
              </div>

              <div className="space-y-2 mb-6">
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">Total Venta:</span>
                  <span className="font-bold text-slate-800">₡{debt.totalAmount.toLocaleString()}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">Total Pagado:</span>
                  <span className="font-bold text-green-600">₡{debt.totalPaid.toLocaleString()}</span>
                </div>
                <div className="flex justify-between text-lg border-t pt-2">
                  <span className="font-bold text-slate-900">Deuda:</span>
                  <span className="font-black text-red-500">₡{(debt.totalAmount - debt.totalPaid).toLocaleString()}</span>
                </div>
              </div>

              <button 
                onClick={() => setSelectedDebt(debt)}
                className="w-full bg-slate-900 text-white py-3 rounded-2xl font-bold text-sm hover:bg-slate-800 transition-all flex items-center justify-center gap-2"
              >
                <i className="fa-solid fa-money-bill-transfer"></i> Registrar Abono
              </button>
            </div>
          ))}
          {debts.length === 0 && (
            <div className="col-span-full py-20 text-center bg-white rounded-3xl border border-dashed border-slate-200">
               <i className="fa-solid fa-face-smile text-4xl text-green-400 mb-2"></i>
               <p className="text-slate-400 font-medium">No hay cuentas pendientes de cobro.</p>
            </div>
          )}
        </div>
      )}

      {selectedDebt && (
        <div className="fixed inset-0 z-[100] bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-200">
             <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-black text-slate-900">REGISTRAR ABONO</h3>
                <button onClick={() => setSelectedDebt(null)} className="text-slate-400 hover:text-slate-600">
                  <i className="fa-solid fa-xmark text-xl"></i>
                </button>
             </div>

             <div className="bg-blue-50 p-4 rounded-2xl mb-6">
                <p className="text-xs text-blue-600 font-bold uppercase mb-1">Cliente</p>
                <p className="text-lg font-black text-blue-900">{selectedDebt.customerName}</p>
                <div className="flex justify-between mt-3 text-sm font-bold text-blue-800">
                  <span>Deuda Actual:</span>
                  <span>₡{(selectedDebt.totalAmount - selectedDebt.totalPaid).toLocaleString()}</span>
                </div>
             </div>

             <div className="space-y-4">
                <div>
                  <label className="text-xs font-bold text-slate-500 uppercase ml-1">Monto del Abono (₡)</label>
                  <input 
                    type="number" 
                    className="w-full px-5 py-4 bg-slate-100 border border-slate-200 rounded-2xl text-xl font-black focus:ring-4 focus:ring-green-500/10 focus:border-green-500 outline-none"
                    placeholder="0"
                    autoFocus
                    value={abonoAmount || ''}
                    onChange={e => setAbonoAmount(Number(e.target.value))}
                  />
                </div>

                <button 
                  onClick={handleRegisterAbono}
                  className="w-full bg-green-600 hover:bg-green-700 text-white py-4 rounded-2xl font-black shadow-lg shadow-green-200 transition-all flex items-center justify-center gap-2"
                >
                  <i className="fa-solid fa-check"></i> Confirmar Abono
                </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ReportsView;

import React, { useState, useMemo } from 'react';
import { InventoryItem } from '../types';
import { generateItemDescription } from '../geminiService';

interface InventoryViewProps {
  inventory: InventoryItem[];
  onUpdateStock: (id: string, amount: number) => void;
  onAddItem: (item: Omit<InventoryItem, 'id' | 'lastUpdated'>) => void;
  onDeleteItem: (id: string) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, onUpdateStock, onAddItem, onDeleteItem }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  // Estados de búsqueda
  const [searchInputValue, setSearchInputValue] = useState('');
  const [appliedSearch, setAppliedSearch] = useState('');

  const [stockInputs, setStockInputs] = useState<Record<string, number>>({});

  const [newItem, setNewItem] = useState({
    sku: '',
    name: '',
    description: '',
    category: '',
    price: 0,
    cost: 0,
    stock: 0
  });

  const filteredItems = useMemo(() => {
    const term = appliedSearch.toLowerCase().trim();
    if (!term) return inventory;

    return inventory.filter(i => {
      const name = String(i.name || '').toLowerCase();
      const sku = String(i.sku || '').toLowerCase();
      const category = String(i.category || '').toLowerCase();
      return name.includes(term) || sku.includes(term) || category.includes(term);
    });
  }, [inventory, appliedSearch]);

  const handleExecuteSearch = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    setAppliedSearch(searchInputValue);
  };

  const handleClearSearch = () => {
    setSearchInputValue('');
    setAppliedSearch('');
  };

  const handleQuickDesc = async () => {
    if (!newItem.name) return;
    setIsGenerating(true);
    const desc = await generateItemDescription(newItem.name);
    setNewItem(prev => ({ ...prev, description: desc }));
    setIsGenerating(false);
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddItem(newItem);
    setNewItem({ sku: '', name: '', description: '', category: '', price: 0, cost: 0, stock: 0 });
    setShowAddModal(false);
  };

  const handleStockUpdate = (id: string) => {
    const amount = stockInputs[id];
    if (amount === undefined || amount <= 0) {
      alert("Por favor digite una cantidad válida.");
      return;
    }
    onUpdateStock(id, amount);
    setStockInputs(prev => ({ ...prev, [id]: 0 }));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">Gestión de Inventario</h3>
          <p className="text-sm text-slate-400 font-medium">Control total de existencias y reposiciones</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-slate-900 hover:bg-slate-800 text-white px-8 py-3.5 rounded-2xl font-bold shadow-xl transition-all flex items-center gap-2 group"
        >
          <i className="fa-solid fa-plus group-hover:rotate-90 transition-transform"></i> Nuevo Artículo
        </button>
      </div>

      <form onSubmit={handleExecuteSearch} className="flex gap-2">
        <div className="relative flex-1 group">
          <input 
            type="text" 
            placeholder="Escriba nombre, SKU o categoría..."
            className="w-full pl-14 pr-4 py-5 bg-white border border-slate-200 rounded-[1.5rem] outline-none focus:ring-4 focus:ring-green-500/10 focus:border-green-500 shadow-sm transition-all font-medium"
            value={searchInputValue}
            onChange={e => setSearchInputValue(e.target.value)}
          />
          <i className="fa-solid fa-magnifying-glass absolute left-6 top-6 text-slate-300 text-lg group-focus-within:text-green-500 transition-colors"></i>
        </div>
        <button 
          type="submit"
          className="bg-green-600 hover:bg-green-700 text-white px-8 rounded-[1.5rem] font-black transition-all shadow-lg active:scale-95 flex items-center gap-2"
        >
          <i className="fa-solid fa-filter"></i> BUSCAR
        </button>
        {appliedSearch && (
          <button 
            type="button"
            onClick={handleClearSearch}
            className="bg-slate-200 hover:bg-slate-300 text-slate-600 px-6 rounded-[1.5rem] font-bold transition-all"
          >
            LIMPIAR
          </button>
        )}
      </form>

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Artículo / SKU</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Categoría</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-center">Precio</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-center">Stock</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Ingresar Stock</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredItems.map(item => (
                <tr key={item.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6">
                    <div className="font-bold text-slate-800 text-base">{item.name}</div>
                    <div className="text-[10px] text-slate-400 font-black tracking-widest uppercase mt-0.5">{item.sku}</div>
                  </td>
                  <td className="px-8 py-6">
                    <span className="px-3 py-1 bg-slate-100 text-slate-500 text-[10px] font-black rounded-full uppercase tracking-tighter">
                      {item.category}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-center font-bold text-slate-700">
                    ₡{item.price.toLocaleString()}
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex justify-center">
                      <span className={`min-w-[40px] h-10 flex items-center justify-center rounded-xl font-black text-sm px-3 ${
                        item.stock <= 5 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'
                      }`}>
                        {item.stock}
                      </span>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-2">
                      <input 
                        type="number" 
                        placeholder="0"
                        className="w-20 px-3 py-2 bg-blue-50 border border-blue-100 rounded-xl text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500"
                        value={stockInputs[item.id] === 0 ? '' : (stockInputs[item.id] || '')}
                        onChange={e => setStockInputs(prev => ({ ...prev, [item.id]: parseInt(e.target.value) || 0 }))}
                      />
                      <button 
                        onClick={() => handleStockUpdate(item.id)}
                        className="bg-green-600 hover:bg-green-700 text-white w-10 h-10 rounded-xl flex items-center justify-center transition-all active:scale-90"
                      >
                        <i className="fa-solid fa-plus text-xs"></i>
                      </button>
                    </div>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <button 
                      onClick={() => { if(confirm('¿Eliminar este artículo?')) onDeleteItem(item.id) }}
                      className="w-10 h-10 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                    >
                      <i className="fa-solid fa-trash-can text-sm"></i>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-xl shadow-2xl animate-in zoom-in duration-200 overflow-hidden">
            <div className="p-10">
              <div className="flex justify-between items-center mb-10">
                <h3 className="text-2xl font-black text-slate-900 tracking-tighter uppercase">NUEVO ARTÍCULO</h3>
                <button onClick={() => setShowAddModal(false)} className="w-12 h-12 flex items-center justify-center rounded-full bg-slate-50 text-slate-400 hover:bg-red-50 hover:text-red-500 transition-all">
                  <i className="fa-solid fa-xmark text-xl"></i>
                </button>
              </div>

              <form onSubmit={handleAddSubmit} className="space-y-6">
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Nombre del Producto</label>
                    <input required type="text" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold" value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">SKU / Código</label>
                    <input required type="text" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold" value={newItem.sku} onChange={e => setNewItem({...newItem, sku: e.target.value})} />
                  </div>
                </div>

                <div className="space-y-2">
                  <div className="flex justify-between items-center px-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Descripción</label>
                    <button type="button" onClick={handleQuickDesc} disabled={!newItem.name || isGenerating} className="text-[10px] text-green-600 font-black hover:bg-green-50 px-2 py-1 rounded-lg">
                      {isGenerating ? 'GENERANDO...' : 'USAR IA'}
                    </button>
                  </div>
                  <textarea className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none h-20 resize-none" value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} />
                </div>

                <div className="grid grid-cols-3 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Precio Venta (₡)</label>
                    <input required type="number" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold" value={newItem.price || ''} onChange={e => setNewItem({...newItem, price: parseFloat(e.target.value)})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Costo (₡)</label>
                    <input required type="number" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold" value={newItem.cost || ''} onChange={e => setNewItem({...newItem, cost: parseFloat(e.target.value)})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Stock Inicial</label>
                    <input required type="number" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold" value={newItem.stock || ''} onChange={e => setNewItem({...newItem, stock: parseInt(e.target.value)})} />
                  </div>
                </div>

                <button type="submit" className="w-full bg-green-600 hover:bg-green-700 text-white py-5 rounded-3xl font-black shadow-xl mt-4">
                  GUARDAR ARTÍCULO
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryView;

import React, { useState, useMemo } from 'react';
import { InventoryItem, Client } from '../types';

interface SalesViewProps {
  inventory: InventoryItem[];
  clients: Client[];
  onSale: (items: { itemId: string, quantity: number }[], isCredit: boolean, customerId: string, initialPayment: number) => void;
}

const SalesView: React.FC<SalesViewProps> = ({ inventory, clients, onSale }) => {
  const [cart, setCart] = useState<{ itemId: string, quantity: number }[]>([]);

  // Estados de búsqueda
  const [searchInputValue, setSearchInputValue] = useState('');
  const [appliedSearch, setAppliedSearch] = useState('');

  const [isCredit, setIsCredit] = useState(false);
  const [selectedClientId, setSelectedClientId] = useState('');
  const [initialPayment, setInitialPayment] = useState(0);

  const filteredItems = useMemo(() => {
    const term = appliedSearch.toLowerCase().trim();
    return inventory.filter(i => {
      const name = String(i.name || '').toLowerCase();
      const sku = String(i.sku || '').toLowerCase();
      const matchesSearch = term === '' || name.includes(term) || sku.includes(term);
      return matchesSearch && Number(i.stock) > 0;
    });
  }, [inventory, appliedSearch]);

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setAppliedSearch(searchInputValue);
  };

  const handleClearSearch = () => {
    setSearchInputValue('');
    setAppliedSearch('');
  };

  const addToCart = (itemId: string) => {
    const item = inventory.find(i => String(i.id) === String(itemId));
    if (!item) return;

    setCart(prev => {
      const existing = prev.find(p => String(p.itemId) === String(itemId));
      if (existing) {
        if (existing.quantity >= Number(item.stock)) {
          alert("Sin stock disponible.");
          return prev;
        }
        return prev.map(p => p.itemId === itemId ? { ...p, quantity: p.quantity + 1 } : p);
      }
      return [...prev, { itemId: itemId, quantity: 1 }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => prev.filter(p => p.itemId !== itemId));
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;
    if (isCredit && !selectedClientId) {
      alert("Seleccione un cliente para crédito.");
      return;
    }
    onSale(cart, isCredit, selectedClientId, initialPayment);
    setCart([]);
    setSelectedClientId('');
    setInitialPayment(0);
    setIsCredit(false);
  };

  const total = useMemo(() => {
    return cart.reduce((acc, curr) => {
      const item = inventory.find(i => String(i.id) === String(curr.itemId));
      return acc + (item ? Number(item.price) * curr.quantity : 0);
    }, 0);
  }, [cart, inventory]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <form onSubmit={handleSearchSubmit} className="flex gap-2 mb-6">
            <div className="relative flex-1">
              <input 
                type="text" 
                placeholder="Nombre o SKU del producto..."
                className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-green-500 transition-all font-medium"
                value={searchInputValue}
                onChange={e => setSearchInputValue(e.target.value)}
              />
              <i className="fa-solid fa-magnifying-glass absolute left-4 top-5 text-slate-400"></i>
            </div>
            <button 
              type="submit"
              className="bg-slate-900 text-white px-6 rounded-2xl font-bold hover:bg-slate-800 transition-all"
            >
              BUSCAR
            </button>
            {appliedSearch && (
              <button 
                type="button"
                onClick={handleClearSearch}
                className="bg-slate-100 text-slate-500 px-4 rounded-2xl font-bold"
              >
                X
              </button>
            )}
          </form>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
            {filteredItems.map(item => (
              <button 
                key={item.id}
                onClick={() => addToCart(item.id)}
                className="flex items-center gap-4 p-4 border border-slate-100 rounded-2xl hover:bg-green-50 hover:border-green-200 transition-all text-left group"
              >
                <div className="w-12 h-12 bg-white border border-slate-100 rounded-xl flex items-center justify-center text-slate-400 group-hover:text-green-600">
                  <i className="fa-solid fa-cart-plus text-lg"></i>
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-bold text-slate-800 leading-tight mb-1 truncate">{item.name}</p>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{item.stock} en stock</p>
                </div>
                <p className="font-black text-green-600 text-lg whitespace-nowrap">₡{item.price.toLocaleString()}</p>
              </button>
            ))}
            {filteredItems.length === 0 && (
              <div className="col-span-full py-10 text-center text-slate-400 italic font-medium">
                No se encontraron productos disponibles.
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="lg:col-span-1">
        <div className="bg-white p-6 rounded-[2.5rem] shadow-xl border border-slate-100 sticky top-8">
          <h3 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-2">
            <i className="fa-solid fa-receipt text-green-600"></i> CARRITO
          </h3>

          <div className="space-y-3 mb-6 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
            {cart.map(c => {
              const item = inventory.find(i => String(i.id) === String(c.itemId));
              return item ? (
                <div key={c.itemId} className="flex justify-between items-center bg-slate-50 p-3 rounded-2xl relative group">
                  <div className="min-w-0 flex-1">
                    <p className="font-bold text-sm leading-tight truncate">{item.name}</p>
                    <p className="text-[10px] font-bold text-slate-400">{c.quantity} un. x ₡{item.price.toLocaleString()}</p>
                  </div>
                  <div className="flex flex-col items-end ml-4">
                    <span className="font-black text-slate-700 text-sm">₡{(item.price * c.quantity).toLocaleString()}</span>
                    <button onClick={() => removeFromCart(c.itemId)} className="text-[10px] text-red-400 font-bold mt-1 opacity-0 group-hover:opacity-100 transition-opacity underline">Quitar</button>
                  </div>
                </div>
              ) : null;
            })}
            {cart.length === 0 && <p className="text-center text-slate-300 py-4 font-bold text-sm italic">Carrito vacío</p>}
          </div>

          <div className="space-y-4 border-t border-slate-100 pt-6">
            <div className="flex bg-slate-100 p-1 rounded-2xl mb-4">
              <button onClick={() => setIsCredit(false)} className={`flex-1 py-2 rounded-xl text-xs font-black transition-all ${!isCredit ? 'bg-white shadow-sm text-green-600' : 'text-slate-500'}`}>CONTADO</button>
              <button onClick={() => setIsCredit(true)} className={`flex-1 py-2 rounded-xl text-xs font-black transition-all ${isCredit ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>CRÉDITO</button>
            </div>

            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cliente</label>
              <select className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none" value={selectedClientId} onChange={e => setSelectedClientId(e.target.value)}>
                <option value="">Consumidor Final</option>
                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>

            {isCredit && (
              <div className="bg-blue-50 p-4 rounded-2xl">
                <label className="block text-[10px] font-black text-blue-400 uppercase mb-2">Abono Inicial (₡)</label>
                <input type="number" className="w-full px-4 py-2 bg-white border border-blue-100 rounded-xl text-lg font-black outline-none" value={initialPayment || ''} onChange={e => setInitialPayment(Number(e.target.value))} placeholder="0" />
              </div>
            )}

            <div className="flex justify-between items-center py-2">
              <span className="text-slate-400 font-bold text-sm">TOTAL</span>
              <span className="text-3xl font-black text-slate-900 tracking-tighter">₡{total.toLocaleString()}</span>
            </div>

            <button disabled={cart.length === 0} onClick={handleCheckout} className={`w-full py-5 rounded-2xl font-black text-white shadow-xl transition-all active:scale-[0.97] ${isCredit ? 'bg-blue-600' : 'bg-green-600'}`}>
              CONFIRMAR {isCredit ? 'CRÉDITO' : 'COBRO'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SalesView;

import React, { useState, useMemo } from 'react';
import { InventoryItem } from '../types';
import { generateItemDescription } from '../geminiService';

interface InventoryViewProps {
  inventory: InventoryItem[];
  onUpdateStock: (id: string, amount: number) => void;
  onAddItem: (item: Omit<InventoryItem, 'id' | 'lastUpdated'>) => void;
  onDeleteItem: (id: string) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, onUpdateStock, onAddItem, onDeleteItem }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  // Estados de búsqueda
  const [inputValue, setInputValue] = useState('');
  const [searchCriteria, setSearchCriteria] = useState('');

  const [stockInputs, setStockInputs] = useState<Record<string, number>>({});

  const [newItem, setNewItem] = useState({
    sku: '',
    name: '',
    description: '',
    category: '',
    price: 0,
    cost: 0,
    stock: 0
  });

  // Función para normalizar texto (quitar acentos y basura)
  const normalize = (text: string) => 
    String(text || '').toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();

  const filteredItems = useMemo(() => {
    const term = normalize(searchCriteria);
    if (!term) return inventory;

    return inventory.filter(i => {
      const name = normalize(i.name);
      const sku = normalize(i.sku);
      const category = normalize(i.category);
      return name.includes(term) || sku.includes(term) || category.includes(term);
    });
  }, [inventory, searchCriteria]);

  const handleApplySearch = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    setSearchCriteria(inputValue);
  };

  const handleClearSearch = () => {
    setInputValue('');
    setSearchCriteria('');
  };

  const handleStockUpdate = (id: string) => {
    const amount = stockInputs[id];
    if (amount === undefined || amount <= 0) {
      alert("Ingrese una cantidad válida para el ajuste.");
      return;
    }
    onUpdateStock(id, amount);
    setStockInputs(prev => ({ ...prev, [id]: 0 }));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">Inventario en Tiempo Real</h3>
