                </tr>
              ))}
              {filteredItems.length === 0 && (
                <tr>
                  <td colSpan={6} className="py-24 text-center">
                    <i className="fa-solid fa-magnifying-glass text-4xl text-slate-100 mb-4 block"></i>
                    <p className="text-slate-400 font-bold">No se encontraron productos que coincidan con "{searchCriteria}"</p>
                    <button onClick={handleClearSearch} className="text-green-600 font-black text-sm mt-4 underline">Ver todo el inventario</button>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-xl shadow-2xl animate-in zoom-in duration-200 overflow-hidden">
