            {isCredit && (
              <div className="bg-blue-50 p-6 rounded-3xl border border-blue-100 animate-in slide-in-from-top-4">
                <label className="block text-[10px] font-black text-blue-500 uppercase tracking-widest mb-3">Abono Inicial (₡)</label>
                <div className="relative">
                   <span className="absolute left-4 top-3 font-black text-blue-300">₡</span>
                   <input type="number" className="w-full pl-10 pr-4 py-3 bg-white border border-blue-200 rounded-xl text-xl font-black text-blue-700 outline-none" value={initialPayment || ''} onChange={e => setInitialPayment(Number(e.target.value))} placeholder="0" />
                </div>
              </div>
            )}

            <div className="flex justify-between items-center bg-slate-900 text-white p-6 rounded-3xl shadow-xl">
              <span className="text-xs font-bold text-slate-400">TOTAL A COBRAR</span>
              <span className="text-3xl font-black tracking-tighter">₡{total.toLocaleString()}</span>
            </div>

            <button 
              disabled={cart.length === 0} 
              onClick={handleCheckout} 
              className={`w-full py-6 rounded-[2rem] font-black text-white shadow-2xl transition-all active:scale-[0.96] flex items-center justify-center gap-3 ${isCredit ? 'bg-blue-600 hover:bg-blue-700' : 'bg-green-600 hover:bg-green-700'}`}
            >
              <i className={`fa-solid ${isCredit ? 'fa-hand-holding-dollar' : 'fa-check-double'}`}></i>
              {isCredit ? 'REALIZAR VENTA A CRÉDITO' : 'PROCESAR COBRO'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SalesView;

import React, { useState, useMemo } from 'react';
import { InventoryItem } from '../types';
import { generateItemDescription } from '../geminiService';

interface InventoryViewProps {
  inventory: InventoryItem[];
  onUpdateStock: (id: string, amount: number) => void;
  onAddItem: (item: Omit<InventoryItem, 'id' | 'lastUpdated'>) => void;
  onDeleteItem: (id: string) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ inventory, onUpdateStock, onAddItem, onDeleteItem }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  // Estado para el texto que escribe el usuario (sin filtrar aun)
  const [tempInputValue, setTempInputValue] = useState('');
  // Estado real que dispara el filtro en el useMemo
  const [activeSearchTerm, setActiveSearchTerm] = useState('');

  const [stockInputs, setStockInputs] = useState<Record<string, number>>({});

  const [newItem, setNewItem] = useState({
    sku: '',
    name: '',
    description: '',
    category: '',
    price: 0,
    cost: 0,
    stock: 0
  });

  // Normalización para ignorar tildes, espacios y mayúsculas
  const normalize = (text: string) => 
    String(text || '').toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();

  // Filtrado optimizado: Solo cambia cuando 'activeSearchTerm' o 'inventory' cambian
  const filteredItems = useMemo(() => {
    const term = normalize(activeSearchTerm);
    if (!term) return inventory;

    return inventory.filter(i => {
      const name = normalize(i.name);
      const sku = normalize(i.sku);
      const category = normalize(i.category);
      return name.includes(term) || sku.includes(term) || category.includes(term);
    });
  }, [inventory, activeSearchTerm]);

  const triggerSearch = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    // Forzamos que el término activo sea lo que hay en el input
    setActiveSearchTerm(tempInputValue);
  };

  const handleClear = () => {
    setTempInputValue('');
    setActiveSearchTerm('');
  };

  const handleStockUpdate = (id: string) => {
    const amount = stockInputs[id];
    if (amount === undefined || amount <= 0) {
      alert("Ingrese una cantidad válida.");
      return;
    }
    onUpdateStock(id, amount);
    setStockInputs(prev => ({ ...prev, [id]: 0 }));
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">Inventario Maestro</h3>
          <p className="text-sm text-slate-400 font-medium">Visualización de artículos y control de stock</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-slate-900 hover:bg-slate-800 text-white px-8 py-3.5 rounded-2xl font-bold shadow-xl transition-all flex items-center gap-2"
        >
          <i className="fa-solid fa-plus"></i> NUEVO ARTÍCULO
        </button>
      </div>

      {/* Buscador Reforzado */}
      <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-100">
        <form onSubmit={triggerSearch} className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1 group">
            <input 
              type="text" 
              placeholder="Buscar por nombre, SKU o categoría..."
              className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-green-500/10 focus:border-green-500 transition-all font-bold text-slate-700"
              value={tempInputValue}
              onChange={e => setTempInputValue(e.target.value)}
            />
            <i className="fa-solid fa-magnifying-glass absolute left-4 top-5 text-slate-300 text-lg group-focus-within:text-green-500 transition-colors"></i>
          </div>
          <div className="flex gap-2">
            <button 
              type="submit"
              className="bg-green-600 hover:bg-green-700 text-white px-10 py-4 rounded-2xl font-black transition-all shadow-lg active:scale-95 flex items-center justify-center gap-2"
            >
              <i className="fa-solid fa-search"></i> BUSCAR
            </button>
            {(tempInputValue || activeSearchTerm) && (
              <button 
                type="button"
                onClick={handleClear}
                className="bg-slate-100 hover:bg-slate-200 text-slate-500 px-6 py-4 rounded-2xl font-bold transition-all"
              >
                LIMPIAR
              </button>
            )}
          </div>
        </form>
      </div>

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest min-w-[250px]">Nombre Completo / SKU</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Categoría</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-center">Precio</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-center">Stock</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest">Ingreso Stock</th>
                <th className="px-8 py-5 font-black text-slate-400 text-[10px] uppercase tracking-widest text-right">Opciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredItems.map(item => (
                <tr key={item.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6 max-w-[300px]">
                    <div className="font-bold text-slate-800 text-base break-words whitespace-normal">{item.name}</div>
                    <div className="text-[10px] text-slate-400 font-black tracking-widest uppercase mt-1">{item.sku}</div>
                  </td>
                  <td className="px-8 py-6">
                    <span className="px-3 py-1 bg-slate-100 text-slate-500 text-[10px] font-black rounded-full uppercase">
                      {item.category}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-center font-bold text-slate-700 whitespace-nowrap">
                    ₡{Number(item.price).toLocaleString()}
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex justify-center">
                      <span className={`min-w-[45px] h-10 flex items-center justify-center rounded-xl font-black text-sm px-3 ${
                        item.stock <= 5 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'
                      }`}>
                        {item.stock}
                      </span>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-2">
                      <input 
                        type="number" 
                        placeholder="0"
                        className="w-20 px-3 py-2 bg-blue-50/50 border border-blue-100 rounded-xl text-sm font-bold outline-none"
                        value={stockInputs[item.id] === 0 ? '' : (stockInputs[item.id] || '')}
                        onChange={e => setStockInputs(prev => ({ ...prev, [item.id]: parseInt(e.target.value) || 0 }))}
                      />
                      <button 
                        onClick={() => handleStockUpdate(item.id)}
                        className="bg-green-600 hover:bg-green-700 text-white w-10 h-10 rounded-xl flex items-center justify-center transition-all active:scale-90 shadow-md shadow-green-100"
                      >
                        <i className="fa-solid fa-plus text-xs"></i>
                      </button>
                    </div>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <button 
                      onClick={() => { if(confirm('¿Eliminar este artículo definitivamente?')) onDeleteItem(item.id) }}
                      className="w-10 h-10 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                    >
                      <i className="fa-solid fa-trash-can"></i>
                    </button>
                  </td>
                </tr>
              ))}
              {filteredItems.length === 0 && (
                <tr>
                  <td colSpan={6} className="py-24 text-center">
                    <i className="fa-solid fa-magnifying-glass text-4xl text-slate-100 mb-4 block"></i>
                    <p className="text-slate-400 font-bold">Sin resultados para "{activeSearchTerm}"</p>
                    <button onClick={handleClear} className="text-green-600 font-black text-sm mt-4 underline decoration-2">Limpiar filtros y ver todo</button>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-xl shadow-2xl animate-in zoom-in duration-200 overflow-hidden">
            <div className="p-10">
              <div className="flex justify-between items-center mb-10">
                <h3 className="text-2xl font-black text-slate-900 tracking-tighter uppercase">NUEVO ARTÍCULO</h3>
                <button onClick={() => setShowAddModal(false)} className="w-12 h-12 flex items-center justify-center rounded-full bg-slate-50 text-slate-400 hover:bg-red-50 hover:text-red-500 transition-all">
                  <i className="fa-solid fa-xmark text-xl"></i>
                </button>
              </div>

              <form onSubmit={(e) => {
                e.preventDefault();
                onAddItem(newItem);
                setNewItem({ sku: '', name: '', description: '', category: '', price: 0, cost: 0, stock: 0 });
                setShowAddModal(false);
              }} className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Nombre del Producto</label>
