import React, { useState, useMemo } from 'react';
import { InventoryItem, Client } from '../types';

interface SalesViewProps {
  inventory: InventoryItem[];
  clients: Client[];
  onSale: (items: { itemId: string, quantity: number }[], isCredit: boolean, customerId: string, initialPayment: number) => void;
}

const SalesView: React.FC<SalesViewProps> = ({ inventory, clients, onSale }) => {
  const [cart, setCart] = useState<{ itemId: string, quantity: number }[]>([]);

  // Estado para el texto que escribe el usuario (sin filtrar aun)
  const [tempInputValue, setTempInputValue] = useState('');
  // Estado real que dispara el filtro en el useMemo
  const [activeSearchTerm, setActiveSearchTerm] = useState('');

  const [isCredit, setIsCredit] = useState(false);
  const [selectedClientId, setSelectedClientId] = useState('');
  const [initialPayment, setInitialPayment] = useState(0);

  // Normalización para búsqueda robusta
  const normalize = (text: string) => 
    String(text || '').toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();

  const filteredItems = useMemo(() => {
    const term = normalize(activeSearchTerm);
    // Solo mostrar items con stock
    const itemsWithStock = inventory.filter(i => Number(i.stock) > 0);

    if (!term) return itemsWithStock;

    return itemsWithStock.filter(i => {
      const name = normalize(i.name);
      const sku = normalize(i.sku);
      return name.includes(term) || sku.includes(term);
    });
  }, [inventory, activeSearchTerm]);

  const handleSearchTrigger = (e: React.FormEvent) => {
    e.preventDefault();
    setActiveSearchTerm(tempInputValue);
  };

  const handleReset = () => {
    setTempInputValue('');
    setActiveSearchTerm('');
  };

  const addToCart = (itemId: string) => {
    const item = inventory.find(i => String(i.id) === String(itemId));
    if (!item) return;

    setCart(prev => {
      const existing = prev.find(p => String(p.itemId) === String(itemId));
      if (existing) {
        if (existing.quantity >= Number(item.stock)) {
          alert(`Límite de stock alcanzado para ${item.name}`);
          return prev;
        }
        return prev.map(p => p.itemId === itemId ? { ...p, quantity: p.quantity + 1 } : p);
      }
      return [...prev, { itemId: itemId, quantity: 1 }];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => prev.filter(p => p.itemId !== itemId));
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;
    if (isCredit && !selectedClientId) {
      alert("Seleccione un cliente para la venta a crédito.");
      return;
    }
    onSale(cart, isCredit, selectedClientId, initialPayment);
    setCart([]);
    setSelectedClientId('');
    setInitialPayment(0);
    setIsCredit(false);
    handleReset();
  };

  const total = useMemo(() => {
    return cart.reduce((acc, curr) => {
      const item = inventory.find(i => String(i.id) === String(curr.itemId));
      return acc + (item ? Number(item.price) * curr.quantity : 0);
    }, 0);
  }, [cart, inventory]);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100">
          <form onSubmit={handleSearchTrigger} className="flex gap-2 mb-8">
            <div className="relative flex-1 group">
              <input 
                type="text" 
                placeholder="Escriba nombre o SKU del producto..."
                className="w-full pl-12 pr-4 py-5 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-green-500/10 focus:border-green-500 transition-all font-bold text-slate-700"
                value={tempInputValue}
                onChange={e => setTempInputValue(e.target.value)}
              />
              <i className="fa-solid fa-magnifying-glass absolute left-4 top-6 text-slate-300 text-lg group-focus-within:text-green-500 transition-colors"></i>
            </div>
            <button 
              type="submit"
              className="bg-slate-900 text-white px-8 rounded-2xl font-black shadow-lg hover:bg-slate-800 transition-all flex items-center gap-2"
            >
              <i className="fa-solid fa-search"></i> BUSCAR
            </button>
            {(tempInputValue || activeSearchTerm) && (
              <button 
                type="button"
                onClick={handleReset}
                className="bg-slate-100 text-slate-500 px-4 rounded-2xl font-bold transition-all"
              >
                X
              </button>
            )}
          </form>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
            {filteredItems.map(item => (
              <button 
                key={item.id}
                onClick={() => addToCart(item.id)}
                className="flex items-start gap-4 p-5 border border-slate-100 rounded-3xl hover:bg-green-50 hover:border-green-200 transition-all text-left group active:scale-[0.98]"
              >
                <div className="w-14 h-14 bg-white border border-slate-100 rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-green-600 shadow-sm shrink-0">
                  <i className="fa-solid fa-cart-plus text-xl"></i>
                </div>
                <div className="flex-1 min-w-0">
                  <p className="font-black text-slate-800 leading-tight mb-1 whitespace-normal break-words">{item.name}</p>
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{item.stock} UNID. EN STOCK</p>
                  <p className="font-black text-green-600 text-lg mt-1">₡{item.price.toLocaleString()}</p>
                </div>
              </button>
            ))}
            {filteredItems.length === 0 && (
              <div className="col-span-full py-20 text-center bg-slate-50 rounded-3xl border border-dashed border-slate-200">
                <i className="fa-solid fa-box-open text-3xl text-slate-300 mb-3 block"></i>
                <p className="text-slate-400 font-bold">Sin resultados para su búsqueda.</p>
                <button onClick={handleReset} className="text-green-600 text-sm font-black underline mt-2">Mostrar todos los productos</button>
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="lg:col-span-1">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl border border-slate-100 sticky top-8">
          <h3 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-3">
            <i className="fa-solid fa-basket-shopping text-green-600"></i> MI CARRITO
          </h3>

          <div className="space-y-4 mb-8 max-h-[350px] overflow-y-auto pr-2 custom-scrollbar">
            {cart.map(c => {
              const item = inventory.find(i => String(i.id) === String(c.itemId));
              return item ? (
                <div key={c.itemId} className="flex justify-between items-start bg-slate-50 p-4 rounded-3xl border border-slate-100 group relative">
                  <div className="min-w-0 flex-1 mr-2">
                    <p className="font-black text-slate-800 text-sm whitespace-normal break-words">{item.name}</p>
                    <p className="text-[10px] font-bold text-slate-400">{c.quantity} un x ₡{item.price.toLocaleString()}</p>
                  </div>
                  <div className="flex flex-col items-end shrink-0">
                    <span className="font-black text-slate-800">₡{(item.price * c.quantity).toLocaleString()}</span>
                    <button onClick={() => removeFromCart(c.itemId)} className="text-[10px] text-red-500 font-black mt-1 opacity-0 group-hover:opacity-100 transition-all uppercase underline">Quitar</button>
                  </div>
                </div>
              ) : null;
            })}
            {cart.length === 0 && (
              <div className="text-center py-10 opacity-30">
                <i className="fa-solid fa-cart-arrow-down text-4xl mb-3 block"></i>
                <p className="font-bold">El carrito está vacío</p>
              </div>
            )}
          </div>

          <div className="space-y-6 border-t border-slate-100 pt-8">
            <div className="flex bg-slate-100 p-1.5 rounded-2xl">
              <button onClick={() => setIsCredit(false)} className={`flex-1 py-3 rounded-xl text-[10px] font-black transition-all ${!isCredit ? 'bg-white shadow-md text-green-600' : 'text-slate-400'}`}>PAGO CONTADO</button>
              <button onClick={() => setIsCredit(true)} className={`flex-1 py-3 rounded-xl text-[10px] font-black transition-all ${isCredit ? 'bg-white shadow-md text-blue-600' : 'text-slate-400'}`}>VENTA CRÉDITO</button>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Cliente</label>
              <select className="w-full px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-black outline-none focus:ring-2 focus:ring-green-500" value={selectedClientId} onChange={e => setSelectedClientId(e.target.value)}>
